  1→import { useCallback, useEffect, useMemo, useRef, useState } from 'react';
  2→import type { EmojiCategory, EmojiEntry } from '../../data/emoji_data';
  3→import {
  4→  EMOJI_CATEGORIES,
  5→  EMOJI_CATEGORY_LABELS,
  6→  EMOJI_CATEGORY_ORDER,
  7→  MOCK_EMOJIS,
  8→} from '../../data/emoji_data';
  9→import { useHUD } from '../../hooks/use_hud';
 10→import { useKeyboardShortcut } from '../../hooks/use_keyboard_shortcut';
 11→import { useNavigation } from '../../hooks/use_navigation';
 12→import { ActionPanel } from '../action_panel/action_panel';
 13→import type { DropdownSection } from '../action_panel/actions_dropdown';
 14→import { EmptyState } from '../empty_state/empty_state';
 15→import { HUDContainer } from '../hud/hud_container';
 16→import { Kbd } from '../kbd/kbd';
 17→import { SearchBar } from '../search_bar/search_bar';
 18→import type { SearchDropdownSection } from '../search_bar/search_dropdown';
 19→import { SearchDropdown } from '../search_bar/search_dropdown';
 20→import './emoji_picker_view.scss';
 21→
 22→const COLUMNS = 6;
 23→const RECENTLY_USED_KEY = 'emoji-picker-recent';
 24→const MAX_RECENT = 12;
 25→
 26→function CopyHUDIcon() {
 27→  return (
 28→    <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
 29→      <path
 30→        d="M3.5 8.5L6.5 11.5L12.5 4.5"
 31→        stroke="currentColor"
 32→        strokeWidth="1.5"
 33→        strokeLinecap="round"
 34→        strokeLinejoin="round"
 35→      />
 36→    </svg>
 37→  );
 38→}
 39→
 40→function SearchEmptyIcon() {
 41→  return (
 42→    <svg width="48" height="48" viewBox="0 0 48 48" fill="none">
 43→      <circle cx="21" cy="21" r="12" stroke="currentColor" strokeWidth="3" />
 44→      <line
 45→        x1="30"
 46→        y1="30"
 47→        x2="42"
 48→        y2="42"
 49→        stroke="currentColor"
 50→        strokeWidth="3"
 51→        strokeLinecap="round"
 52→      />
 53→    </svg>
 54→  );
 55→}
 56→
 57→function loadRecentEmojis(): string[] {
 58→  try {
 59→    const stored = localStorage.getItem(RECENTLY_USED_KEY);
 60→    if (!stored) return [];
 61→    const parsed: unknown = JSON.parse(stored);
 62→    if (!Array.isArray(parsed)) return [];
 63→    return parsed.filter((v): v is string => typeof v === 'string');
 64→  } catch {
 65→    return [];
 66→  }
 67→}
 68→
 69→function saveRecentEmojis(chars: string[]) {
 70→  try {
 71→    localStorage.setItem(RECENTLY_USED_KEY, JSON.stringify(chars));
 72→  } catch (_) {
 73→    /* storage unavailable */
 74→  }
 75→}
 76→
 77→interface EmojiSection {
 78→  title: string;
 79→  emojis: EmojiEntry[];
 80→}
 81→
 82→const FILTER_SECTIONS: SearchDropdownSection[] = [
 83→  {
 84→    options: [
 85→      {
 86→        label: 'All',
 87→        value: 'all',
 88→      },
 89→    ],
 90→  },
 91→  {
 92→    title: 'Category',
 93→    options: EMOJI_CATEGORIES.map(c => ({
 94→      label: c.label,
 95→      value: c.value,
 96→    })),
 97→  },
 98→];
 99→
100→export function EmojiPickerView() {
101→  const nav = useNavigation();
102→  const [query, setQuery] = useState('');
103→  const [filterValue, setFilterValue] = useState('all');
104→  const [activeIndex, setActiveIndex] = useState(0);
105→  const [actionsOpen, setActionsOpen] = useState(false);
106→  const [recentChars, setRecentChars] = useState<string[]>(loadRecentEmojis);
107→  const { items: hudItems, show: showHUD } = useHUD();
108→  const containerRef = useRef<HTMLDivElement>(null);
109→
110→  const emojiLookup = useMemo(() => {
111→    const map = new Map<string, EmojiEntry>();
112→    for (const e of MOCK_EMOJIS) {
113→      map.set(e.char, e);
114→    }
115→    return map;
116→  }, []);
117→
118→  const recentEmojis = useMemo(
119→    () =>
120→      recentChars
121→        .map(char => emojiLookup.get(char))
122→        .filter((e): e is EmojiEntry => e !== undefined),
123→    [
124→      recentChars,
125→      emojiLookup,
126→    ],
127→  );
128→
129→  const filtered = useMemo(() => {
130→    let emojis = MOCK_EMOJIS;
131→    if (filterValue !== 'all') {
132→      emojis = emojis.filter(e => e.category === filterValue);
133→    }
134→    if (query) {
135→      const lower = query.toLowerCase();
136→      emojis = emojis.filter(
137→        e =>
138→          e.name.toLowerCase().includes(lower) ||
139→          e.keywords.some(k => k.includes(lower)) ||
140→          e.char === query,
141→      );
142→    }
143→    return emojis;
144→  }, [
145→    query,
146→    filterValue,
147→  ]);
148→
149→  const sections = useMemo(() => {
150→    const result: EmojiSection[] = [];
151→
152→    if (!query && filterValue === 'all' && recentEmojis.length > 0) {
153→      result.push({
154→        title: 'Recently Used',
155→        emojis: recentEmojis,
156→      });
157→    }
158→
159→    const grouped = new Map<EmojiCategory, EmojiEntry[]>();
160→    for (const emoji of filtered) {
161→      const existing = grouped.get(emoji.category);
162→      if (existing) {
163→        existing.push(emoji);
164→      } else {
165→        grouped.set(emoji.category, [emoji]);
166→      }
167→    }
168→
169→    for (const cat of EMOJI_CATEGORY_ORDER) {
170→      const items = grouped.get(cat);
171→      if (items && items.length > 0) {
172→        result.push({
173→          title: EMOJI_CATEGORY_LABELS[cat],
174→          emojis: items,
175→        });
176→      }
177→    }
178→
179→    return result;
180→  }, [
181→    filtered,
182→    query,
183→    filterValue,
184→    recentEmojis,
185→  ]);
186→
187→  const flatEmojis = useMemo(() => sections.flatMap(s => s.emojis), [sections]);
188→  const totalCount = flatEmojis.length;
189→
190→  useEffect(() => {
191→    if (totalCount === 0) {
192→      setActiveIndex(0);
193→    } else if (activeIndex >= totalCount) {
194→      setActiveIndex(totalCount - 1);
195→    }
196→  }, [
197→    totalCount,
198→    activeIndex,
199→  ]);
200→
201→  useEffect(() => {
202→    const container = containerRef.current;
203→    if (!container) return;
204→    const el = container.querySelector<HTMLElement>(
205→      `[data-emoji-index="${activeIndex}"]`,
206→    );
207→    el?.scrollIntoView({ block: 'nearest' });
208→  }, [activeIndex]);
209→
210→  const selectedEmoji = flatEmojis[activeIndex];
211→
212→  const addToRecent = useCallback((char: string) => {
213→    setRecentChars(prev => {
214→      const next = [
215→        char,
216→        ...prev.filter(c => c !== char),
217→      ].slice(0, MAX_RECENT);
218→      saveRecentEmojis(next);
219→      return next;
220→    });
221→  }, []);
222→
223→  const handleCopyEmoji = useCallback(
224→    (emoji?: EmojiEntry) => {
225→      const target = emoji ?? selectedEmoji;
226→      if (!target) return;
227→      navigator.clipboard.writeText(target.char).catch(() => {});
228→      setActionsOpen(false);
229→      addToRecent(target.char);
230→      showHUD({
231→        icon: <CopyHUDIcon />,
232→        title: `Copied ${target.char}`,
233→      });
234→    },
235→    [
236→      selectedEmoji,
237→      showHUD,
238→      addToRecent,
239→    ],
240→  );
241→
242→  const handleQueryChange = useCallback((value: string) => {
243→    setQuery(value);
244→    setActiveIndex(0);
245→    setActionsOpen(false);
246→  }, []);
247→
248→  const handleFilterChange = useCallback((value: string) => {
249→    setFilterValue(value);
250→    setActiveIndex(0);
251→  }, []);
252→
253→  const toggleActions = useCallback(() => {
254→    setActionsOpen(prev => !prev);
255→  }, []);
256→
257→  const closeActions = useCallback(() => {
258→    setActionsOpen(false);
259→  }, []);
260→
261→  useKeyboardShortcut(
262→    {
263→      key: 'k',
264→      meta: true,
265→    },
266→    toggleActions,
267→  );
268→  useKeyboardShortcut(
269→    {
270→      key: 'c',
271→      meta: true,
272→    },
273→    () => handleCopyEmoji(),
274→  );
275→
276→  useEffect(() => {
277→    function handleKeyDown(e: KeyboardEvent) {
278→      if (totalCount === 0) return;
279→      if (e.metaKey || e.ctrlKey || e.altKey) return;
280→
281→      const isTextInput =
282→        e.target instanceof HTMLInputElement ||
283→        e.target instanceof HTMLTextAreaElement;
284→
285→      switch (e.key) {
286→        case 'ArrowRight': {
287→          if (isTextInput) return;
288→          e.preventDefault();
289→          setActiveIndex(prev => (prev + 1 < totalCount ? prev + 1 : 0));
290→          break;
291→        }
292→        case 'ArrowLeft': {
293→          if (isTextInput) return;
294→          e.preventDefault();
295→          setActiveIndex(prev => (prev - 1 >= 0 ? prev - 1 : totalCount - 1));
296→          break;
297→        }
298→        case 'ArrowDown': {
299→          e.preventDefault();
300→          setActiveIndex(prev => {
301→            const sectionInfo = getSectionInfo(prev);
302→            if (!sectionInfo) return prev;
303→            const { sectionStart, sectionLength } = sectionInfo;
304→            const posInSection = prev - sectionStart;
305→            const row = Math.floor(posInSection / COLUMNS);
306→            const col = posInSection % COLUMNS;
307→            const sectionRows = Math.ceil(sectionLength / COLUMNS);
308→
309→            if (row + 1 < sectionRows) {
310→              const nextIdx = sectionStart + (row + 1) * COLUMNS + col;
311→              return nextIdx < sectionStart + sectionLength
312→                ? nextIdx
313→                : sectionStart + sectionLength - 1;
314→            }
315→
316→            const nextSectionStart = sectionStart + sectionLength;
317→            if (nextSectionStart < totalCount) {
318→              const nextInfo = getSectionInfo(nextSectionStart);
319→              if (!nextInfo) return prev;
320→              const targetIdx = nextSectionStart + col;
321→              return targetIdx < nextSectionStart + nextInfo.sectionLength
322→                ? targetIdx
323→                : nextSectionStart + nextInfo.sectionLength - 1;
324→            }
325→
326→            return prev;
327→          });
328→          break;
329→        }
330→        case 'ArrowUp': {
331→          e.preventDefault();
332→          setActiveIndex(prev => {
333→            const sectionInfo = getSectionInfo(prev);
334→            if (!sectionInfo) return prev;
335→            const { sectionStart } = sectionInfo;
336→            const posInSection = prev - sectionStart;
337→            const row = Math.floor(posInSection / COLUMNS);
338→            const col = posInSection % COLUMNS;
339→
340→            if (row > 0) {
341→              return sectionStart + (row - 1) * COLUMNS + col;
342→            }
343→
344→            if (sectionStart > 0) {
345→              const prevSectionEnd = sectionStart - 1;
346→              const prevInfo = getSectionInfo(prevSectionEnd);
347→              if (!prevInfo) return prev;
348→              const prevSectionRows = Math.ceil(
349→                prevInfo.sectionLength / COLUMNS,
350→              );
351→              const lastRowStart =
352→                prevInfo.sectionStart + (prevSectionRows - 1) * COLUMNS;
353→              const targetIdx = lastRowStart + col;
354→              return targetIdx < prevInfo.sectionStart + prevInfo.sectionLength
355→                ? targetIdx
356→                : prevInfo.sectionStart + prevInfo.sectionLength - 1;
357→            }
358→
359→            return prev;
360→          });
361→          break;
362→        }
363→        case 'Enter': {
364→          e.preventDefault();
365→          handleCopyEmoji();
366→          break;
367→        }
368→      }
369→    }
370→
371→    window.addEventListener('keydown', handleKeyDown);
372→    return () => window.removeEventListener('keydown', handleKeyDown);
373→  }, [
374→    totalCount,
375→    handleCopyEmoji,
376→    sections,
377→  ]);
378→
379→  const sectionBoundaries = useMemo(() => {
380→    const boundaries: {
381→      start: number;
382→      length: number;
383→    }[] = [];
384→    let offset = 0;
385→    for (const section of sections) {
386→      boundaries.push({
387→        start: offset,
388→        length: section.emojis.length,
389→      });
390→      offset += section.emojis.length;
391→    }
392→    return boundaries;
393→  }, [sections]);
394→
395→  function getSectionInfo(index: number) {
396→    for (const b of sectionBoundaries) {
397→      if (index >= b.start && index < b.start + b.length) {
398→        return {
399→          sectionStart: b.start,
400→          sectionLength: b.length,
401→        };
402→      }
403→    }
404→    return null;
405→  }
406→
407→  const dropdownSections: DropdownSection[] = useMemo(
408→    () => [
409→      {
410→        title: 'Actions',
411→        actions: [
412→          {
413→            label: 'Copy Emoji',
414→            shortcut: <Kbd keys={['↵']} />,
415→            onClick: () => handleCopyEmoji(),
416→          },
417→          {
418→            label: 'Copy to Clipboard',
419→            shortcut: (
420→              <Kbd
421→                keys={[
422→                  '⌘',
423→                  'C',
424→                ]}
425→              />
426→            ),
427→            onClick: () => handleCopyEmoji(),
428→          },
429→        ],
430→      },
431→    ],
432→    [handleCopyEmoji],
433→  );
434→
435→  const handleGridMouseOver = useCallback(
436→    (e: React.MouseEvent<HTMLDivElement>) => {
437→      const target = (e.target as HTMLElement).closest<HTMLElement>(
438→        '[data-emoji-index]',
439→      );
440→      if (!target) return;
441→      const idx = Number(target.dataset.emojiIndex);
442→      if (!Number.isNaN(idx) && idx !== activeIndex) {
443→        setActiveIndex(idx);
444→      }
445→    },
446→    [activeIndex],
447→  );
448→
449→  const activeDescendantId =
450→    totalCount > 0 ? `emoji-item-${activeIndex}` : undefined;
451→
452→  return (
453→    <>
454→      <SearchBar
455→        value={query}
456→        onChange={handleQueryChange}
457→        placeholder="Search Emoji..."
458→        activeDescendantId={activeDescendantId}
459→        breadcrumbs={nav.breadcrumbs.length > 0 ? nav.breadcrumbs : undefined}
460→        dropdown={
461→          <SearchDropdown
462→            sections={FILTER_SECTIONS}
463→            value={filterValue}
464→            onChange={handleFilterChange}
465→          />
466→        }
467→      />
468→      <div className="command-palette__body">
469→        <div className="command-palette__list-container">
470→          {totalCount === 0 ? (
471→            <EmptyState
472→              icon={<SearchEmptyIcon />}
473→              title="No Emoji Found"
474→              description={
475→                query
476→                  ? 'Try a different search term'
477→                  : 'No emojis in this category'
478→              }
479→            />
480→          ) : (
481→            <div
482→              ref={containerRef}
483→              className="emoji-picker"
484→              role="listbox"
485→              id="emoji-grid"
486→              aria-label="Emoji list"
487→              onMouseOver={handleGridMouseOver}
488→            >
489→              {(() => {
490→                let globalIndex = 0;
491→                return sections.map(section => (
492→                  <div key={section.title} className="emoji-picker__section">
493→                    <div className="emoji-picker__section-header">
494→                      {section.title}
495→                    </div>
496→                    <div className="emoji-picker__grid">
497→                      {section.emojis.map(emoji => {
498→                        const idx = globalIndex++;
499→                        const isActive = idx === activeIndex;
500→                        return (
501→                          <div
502→                            key={`${section.title}-${emoji.char}`}
503→                            id={`emoji-item-${idx}`}
504→                            className={`emoji-picker__cell${isActive ? ' emoji-picker__cell--active' : ''}`}
505→                            role="option"
506→                            aria-selected={isActive}
507→                            aria-label={emoji.name}
508→                            data-emoji-index={idx}
509→                            onClick={() => {
510→                              setActiveIndex(idx);
511→                              handleCopyEmoji(emoji);
512→                            }}
513→                          >
514→                            {emoji.char}
515→                          </div>
516→                        );
517→                      })}
518→                    </div>
519→                  </div>
520→                ));
521→              })()}
522→            </div>
523→          )}
524→        </div>
525→      </div>
526→      <ActionPanel
527→        contextLabel="Emoji"
528→        actions={[
529→          {
530→            label: selectedEmoji ? `Copy ${selectedEmoji.char}` : 'Copy Emoji',
531→            shortcut: <Kbd keys={['↵']} />,
532→          },
533→          {
534→            label: 'Actions',
535→            shortcut: (
536→              <Kbd
537→                keys={[
538→                  '⌘',
539→                  'K',
540→                ]}
541→              />
542→            ),
543→            onClick: toggleActions,
544→          },
545→        ]}
546→        dropdownOpen={actionsOpen}
547→        dropdownSections={dropdownSections}
548→        onDropdownClose={closeActions}
549→      />
550→      <HUDContainer items={hudItems} />
551→    </>
552→  );
553→}
