  1→import { useCallback, useEffect, useMemo, useState } from 'react';
  2→import { ActionPanel } from './components/action_panel/action_panel';
  3→import { Alert } from './components/alert/alert';
  4→import { ClipboardHistoryView } from './components/clipboard_history/clipboard_history_view';
  5→import { CommandPalette } from './components/command_palette/command_palette';
  6→import { Detail } from './components/detail/detail';
  7→import { DetailMetadata } from './components/detail/detail_metadata';
  8→import { EmojiPickerView } from './components/emoji_picker/emoji_picker_view';
  9→import { EmptyState } from './components/empty_state/empty_state';
 10→import { Grid, GridItem } from './components/grid';
 11→import { HUDContainer } from './components/hud/hud_container';
 12→import { Kbd } from './components/kbd/kbd';
 13→import { List, ListItem, ListSection } from './components/list';
 14→import { QuickLook } from './components/quick_look/quick_look';
 15→import { SearchBar } from './components/search_bar/search_bar';
 16→import type { SearchDropdownSection } from './components/search_bar/search_dropdown';
 17→import { SearchDropdown } from './components/search_bar/search_dropdown';
 18→import { SnippetManagerView } from './components/snippet_manager/snippet_manager_view';
 19→import { ToastContainer } from './components/toast/toast_container';
 20→import { MOCK_COLORS, MOCK_SECTIONS } from './data/mock_data';
 21→import { useAlert } from './hooks/use_alert';
 22→import { useHUD } from './hooks/use_hud';
 23→import { useKeyboardShortcut } from './hooks/use_keyboard_shortcut';
 24→import {
 25→  NavigationContextProvider,
 26→  useNavigationStack,
 27→} from './hooks/use_navigation';
 28→import { useToast } from './hooks/use_toast';
 29→import type {
 30→  ColorItemData,
 31→  ListItemData,
 32→  ListItemMetadataEntry,
 33→  SectionData,
 34→} from './types';
 35→
 36→type NavViewData =
 37→  | { type: 'grid' }
 38→  | { type: 'clipboard' }
 39→  | { type: 'snippets' }
 40→  | { type: 'emoji' }
 41→  | {
 42→      type: 'detail';
 43→      item: ListItemData;
 44→    };
 45→
 46→function filterSections(sections: SectionData[], query: string): SectionData[] {
 47→  if (!query) return sections;
 48→  const lower = query.toLowerCase();
 49→  return sections
 50→    .map(section => ({
 51→      ...section,
 52→      items: section.items.filter(
 53→        item =>
 54→          item.title.toLowerCase().includes(lower) ||
 55→          item.subtitle?.toLowerCase().includes(lower),
 56→      ),
 57→    }))
 58→    .filter(section => section.items.length > 0);
 59→}
 60→
 61→function filterColors(colors: ColorItemData[], query: string): ColorItemData[] {
 62→  if (!query) return colors;
 63→  const lower = query.toLowerCase();
 64→  return colors.filter(
 65→    c =>
 66→      c.title.toLowerCase().includes(lower) ||
 67→      c.subtitle?.toLowerCase().includes(lower),
 68→  );
 69→}
 70→
 71→function flattenItems(sections: SectionData[]): ListItemData[] {
 72→  return sections.flatMap(s => s.items);
 73→}
 74→
 75→function renderMetadataEntry(entry: ListItemMetadataEntry, index: number) {
 76→  switch (entry.type) {
 77→    case 'label':
 78→      return (
 79→        <DetailMetadata.Label
 80→          key={index}
 81→          title={entry.title}
 82→          text={entry.text}
 83→        />
 84→      );
 85→    case 'link':
 86→      return (
 87→        <DetailMetadata.Link
 88→          key={index}
 89→          title={entry.title}
 90→          text={entry.text}
 91→          target={entry.target}
 92→        />
 93→      );
 94→    case 'tag-list':
 95→      return (
 96→        <DetailMetadata.TagList key={index} title={entry.title}>
 97→          {entry.tags.map(tag => (
 98→            <DetailMetadata.Tag
 99→              key={tag.text}
