112→interface SnippetFormState {
113→  name: string;
114→  keyword: string;
115→  snippet: string;
116→  category: SnippetCategory;
117→  tags: string[];
118→}
119→
120→const INITIAL_SNIPPET_FORM: SnippetFormState = {
121→  name: '',
122→  keyword: '',
123→  snippet: '',
124→  category: 'general',
125→  tags: [],
126→};
127→
128→const FORM_TAG_OPTIONS = SNIPPET_TAGS.map(t => ({
129→  label: t.label,
130→  value: t.value,
131→}));
132→
133→const FORM_CATEGORY_OPTIONS = SNIPPET_CATEGORIES.map(c => ({
134→  label: c.label,
135→  value: c.value,
136→}));
137→
138→interface EditSnippetViewProps {
139→  snippet?: SnippetEntry;
140→  onSubmit: (form: SnippetFormState) => void;
141→}
142→
143→function EditSnippetView({ snippet, onSubmit }: EditSnippetViewProps) {
144→  const [form, setForm] = useState<SnippetFormState>(() => {
145→    if (snippet) {
146→      return {
147→        name: snippet.name,
148→        keyword: snippet.keyword,
149→        snippet: snippet.content,
150→        category: snippet.category,
151→        tags: snippet.tags.map(t => t.text.toLowerCase()),
152→      };
153→    }
154→    return INITIAL_SNIPPET_FORM;
155→  });
156→  const [errors, setErrors] = useState<
157→    Partial<Record<keyof SnippetFormState, string>>
158→  >({});
159→
160→  const handleSubmit = useCallback(() => {
161→    const newErrors: Partial<Record<keyof SnippetFormState, string>> = {};
162→    if (!form.name.trim()) {
163→      newErrors.name = 'Name is required';
164→    }
165→    if (!form.snippet.trim()) {
166→      newErrors.snippet = 'Snippet content is required';
167→    }
168→    setErrors(newErrors);
169→    if (Object.keys(newErrors).length > 0) return;
170→    onSubmit(form);
171→  }, [
172→    form,
173→    onSubmit,
174→  ]);
175→
176→  useKeyboardShortcut(
177→    {
178→      key: 'Enter',
179→      meta: true,
180→    },
181→    handleSubmit,
182→  );
183→
184→  return (
185→    <Form onSubmit={handleSubmit}>
186→      <FormTextField
187→        label="Name"
188→        value={form.name}
189→        onChange={v =>
190→          setForm(prev => ({
191→            ...prev,
192→            name: v,
193→          }))
194→        }
195→        placeholder="e.g. Email Signature"
196→        error={errors.name}
197→        autoFocus
198→      />
199→      <FormTextField
200→        label="Keyword"
201→        value={form.keyword}
202→        onChange={v =>
203→          setForm(prev => ({
204→            ...prev,
205→            keyword: v,
206→          }))
207→        }
208→        placeholder="e.g. !sig"
209→        description="Type this to expand the snippet"
210→      />
211→      <FormDropdown
212→        label="Category"
213→        value={form.category}
214→        onChange={v => {
215→          if (isSnippetCategory(v)) {
216→            setForm(prev => ({
217→              ...prev,
218→              category: v,
219→            }));
220→          }
221→        }}
222→        options={FORM_CATEGORY_OPTIONS}
223→        placeholder="Select a category"
224→      />
225→      <FormTagPicker
226→        label="Tags"
227→        value={form.tags}
228→        onChange={v =>
229→          setForm(prev => ({
230→            ...prev,
231→            tags: v,
232→          }))
233→        }
234→        options={FORM_TAG_OPTIONS}
235→        placeholder="Add tags..."
236→        description="Categorize your snippet with tags"
237→      />
238→      <FormTextArea
239→        label="Snippet"
240→        value={form.snippet}
241→        onChange={v =>
242→          setForm(prev => ({
243→            ...prev,
244→            snippet: v,
245→          }))
246→        }
247→        placeholder="Enter your snippet content..."
248→        error={errors.snippet}
249→        rows={5}
250→      />
251→    </Form>
252→  );
253→}
