263→  const [actionsOpen, setActionsOpen] = useState(false);
264→  const [subView, setSubView] = useState<SnippetSubView>('list');
265→  const [editingSnippet, setEditingSnippet] = useState<
266→    SnippetEntry | undefined
267→  >();
