274→    if (filterValue !== 'all') {
275→      items = items.filter(e => e.category === filterValue);
276→    }
277→    if (query) {
278→      const lower = query.toLowerCase();
279→      items = items.filter(
280→        e =>
281→          e.name.toLowerCase().includes(lower) ||
282→          e.keyword.toLowerCase().includes(lower) ||
283→          e.content.toLowerCase().includes(lower),
284→      );
285→    }
286→    return items;
287→  }, [
288→    entries,
289→    query,
290→    filterValue,
291→  ]);
292→
293→  const groupedByCategory = useMemo(() => {
294→    const groups: {
295→      title: string;
296→      items: SnippetEntry[];
297→    }[] = [];
